package jetbrains.mps.lang.resources.iconGeneration;

/*Generated by MPS */


public class IconFileNameUtil {
  public static String createDarkSchemeNameForIcon(final String iconFileName) {
    if ((iconFileName == null || iconFileName.length() == 0)) {
      return iconFileName;
    }
    int lastDotPosition = iconFileName.lastIndexOf(".");
    if (lastDotPosition == -1) {
      return iconFileName + "_dark";
    }
    return iconFileName.substring(0, lastDotPosition) + "_dark" + iconFileName.substring(lastDotPosition);
  }
}
